function hasClass(node, cls) {
  const list = String(node.className || '').split(/\s+/).filter(Boolean);
  return list.includes(cls);
}

function matchesSimple(node, selector) {
  const s = String(selector || '').trim();
  if (!s) return false;

  // .class
  if (s.startsWith('.')) {
    return hasClass(node, s.slice(1));
  }

  // tag or tag.class
  const parts = s.split('.');
  const tag = parts[0];
  const cls = parts[1];

  if (tag) {
    if (String(node.tagName || '').toLowerCase() !== tag.toLowerCase()) return false;
  }
  if (cls) {
    if (!hasClass(node, cls)) return false;
  }
  return true;
}

export default function closestWithin(node, selector, boundary) {
  if (!node) return null;

  let cur = node;
  while (cur) {
    if (matchesSimple(cur, selector)) return cur;
    if (boundary && cur === boundary) return null;
    cur = cur.parentNode || null;
  }
  return null;
}
